package pong

import (
	"bufio"
	"fmt"
	"math/rand"
	"os"
	"os/exec"
	"strings"
	"time"
)

const (
	width      = 60
	height     = 20
	paddleSize = 4
)

// Game holds the state of a Pong match.
type Game struct {
	ballX, ballY   int
	ballDX, ballDY int
	leftY          int
	rightY         int
	leftScore      int
	rightScore     int
	paused         bool
	quit           bool
	tick           time.Duration
}

// New constructs a Game with the ball served toward a random player.
func New() *Game {
	g := &Game{
		ballDX:  1,
		ballDY:  1,
		leftY:   height/2 - paddleSize/2,
		rightY:  height/2 - paddleSize/2,
		tick:    80 * time.Millisecond,
	}
	if rand.Intn(2) == 0 {
		g.ballDX = -1
	}
	return g
}

// ResetBall recenters the ball and serves it toward the player who conceded.
func (g *Game) ResetBall(towardLeft bool) {
	g.ballX = width / 2
	g.ballY = height / 2
	g.ballDX = 1
	g.ballDY = []int{-1, 1}[rand.Intn(2)]
	if towardLeft {
		g.ballDX = -1
	}
}

// Step advances the simulation by one tick.
func (g *Game) Step() {
	if g.paused || g.quit {
		return
	}

	nextX := g.ballX + g.ballDX
	nextY := g.ballY + g.ballDY

	// Top/bottom wall bounce.
	if nextY <= 0 || nextY >= height-1 {
		g.ballDY = -g.ballDY
		nextY = g.ballY + g.ballDY
	}

	// Left paddle collision.
	if nextX == 1 && g.ballDX < 0 {
		if nextY >= g.leftY && nextY < g.leftY+paddleSize {
			g.ballDX = -g.ballDX
			nextX = g.ballX + g.ballDX
		}
	}

	// Right paddle collision.
	if nextX == width-2 && g.ballDX > 0 {
		if nextY >= g.rightY && nextY < g.rightY+paddleSize {
			g.ballDX = -g.ballDX
			nextX = g.ballX + g.ballDX
		}
	}

	// Scoring.
	if nextX <= 0 {
		g.rightScore++
		g.ResetBall(true)
		return
	}
	if nextX >= width-1 {
		g.leftScore++
		g.ResetBall(false)
		return
	}

	g.ballX = nextX
	g.ballY = nextY
}

// MoveLeftPaddle clamps the paddle inside the playfield.
func (g *Game) MoveLeftPaddle(delta int) {
	g.leftY = clamp(g.leftY+delta, 0, height-paddleSize)
}

// MoveRightPaddle clamps the paddle inside the playfield.
func (g *Game) MoveRightPaddle(delta int) {
	g.rightY = clamp(g.rightY+delta, 0, height-paddleSize)
}

// TogglePause flips the paused flag.
func (g *Game) TogglePause() {
	g.paused = !g.paused
}

// Quit ends the match.
func (g *Game) Quit() {
	g.quit = true
}

// Over reports whether either player has reached the winning score.
func (g *Game) Over() bool {
	return g.leftScore >= 5 || g.rightScore >= 5
}

// Winner returns the side that has reached the winning score, or "" if ongoing.
func (g *Game) Winner() string {
	if g.leftScore >= 5 {
		return "LEFT"
	}
	if g.rightScore >= 5 {
		return "RIGHT"
	}
	return ""
}

// Render draws the current frame to a string.
func (g *Game) Render() string {
	grid := make([][]rune, height)
	for i := range grid {
		grid[i] = make([]rune, width)
		for j := range grid[i] {
			grid[i][j] = ' '
		}
	}

	// Top and bottom borders.
	for x := 0; x < width; x++ {
		grid[0][x] = '-'
		grid[height-1][x] = '-'
	}

	// Net.
	for y := 1; y < height-1; y++ {
		if y%2 == 0 {
			grid[y][width/2] = '|'
		}
	}

	// Paddles.
	for i := 0; i < paddleSize; i++ {
		grid[g.leftY+i][0] = '#'
		grid[g.rightY+i][width-1] = '#'
	}

	// Ball.
	if g.ballY >= 0 && g.ballY < height && g.ballX >= 0 && g.ballX < width {
		grid[g.ballY][g.ballX] = 'O'
	}

	var b strings.Builder
	fmt.Fprintf(&b, "PONG  %2d : %-2d   (w/s=left, o/l=right, p=pause, q=quit)\n",
		g.leftScore, g.rightScore)
	for _, row := range grid {
		b.WriteString(string(row))
		b.WriteByte('\n')
	}
	return b.String()
}

func clamp(v, lo, hi int) int {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

// Run launches the interactive loop. It blocks until the player quits.
func (g *Game) Run(in *bufio.Reader) error {
	if err := enableRawMode(); err != nil {
		return err
	}
	defer disableRawMode()

	if err := clearScreen(); err != nil {
		return err
	}

	for !g.quit {
		fmt.Print("\x1b[H")
		fmt.Print(g.Render())
		if g.Over() {
			fmt.Printf("\n%s wins! Press q to exit.\n", g.Winner())
		}

		select {
		case key := <-keyChan():
			switch key {
			case 'q', 'Q':
				g.Quit()
			case 'p', 'P':
				g.TogglePause()
			case 'w', 'W':
				g.MoveLeftPaddle(-1)
			case 's', 'S':
				g.MoveLeftPaddle(1)
			case 'o', 'O':
				g.MoveRightPaddle(-1)
			case 'l', 'L':
				g.MoveRightPaddle(1)
			}
		case <-time.After(g.tick):
		}

		if g.Over() {
			// Drain input until the player quits.
			for {
				select {
				case key := <-keyChan():
					if key == 'q' || key == 'Q' {
						g.Quit()
						return nil
					}
				case <-time.After(50 * time.Millisecond):
				}
			}
		}

		g.Step()
	}
	return nil
}

// keyChan returns a channel that yields one rune per keystroke.
// It is intentionally simple: a goroutine reads stdin in raw mode and
// forwards each rune. The channel is buffered so the game loop never blocks.
func keyChan() <-chan rune {
	ch := make(chan rune, 4)
	go func() {
		defer close(ch)
		buf := make([]byte, 1)
		for {
			n, err := os.Stdin.Read(buf)
			if err != nil || n == 0 {
				return
			}
			ch <- rune(buf[0])
		}
	}()
	return ch
}

func enableRawMode() error {
	// Best-effort: rely on the terminal already being in raw mode when piped
	// via `stty raw -echo`. We still try to set it explicitly.
	cmd := exec.Command("stty", "raw", "-echo")
	cmd.Stdin = os.Stdin
	return cmd.Run()
}

func disableRawMode() error {
	cmd := exec.Command("stty", "sane")
	cmd.Stdin = os.Stdin
	return cmd.Run()
}

func clearScreen() error {
	_, err := os.Stdout.WriteString("\x1b[2J")
	return err
}
